/** 平台 → 图标子组件映射 */
const ICON_MAP: Record<PlatformType, React.FC<{ size: number }>> = {
  bilibili: BilibiliIcon,
  youtube: YouTubeIcon,
  google: GoogleIcon,
  github: GitHubIcon,
  zhihu: ZhihuIcon,
  xiaohongshu: XiaohongshuIcon,
  wechat: WeChatIcon,
  stackoverflow: StackOverflowIcon,
  arxiv: ArxivIcon,
  tavily: TavilyIcon,
  other: OtherIcon,
}

/**
 * 统一平台图标组件
 *
 * @example
 * <PlatformIcon platform="bilibili" size={16} />
 */
export const PlatformIcon: React.FC<PlatformIconProps> = ({
  platform,
  size = 16,
  className,
}) => {
  const Icon = ICON_MAP[platform] ?? OtherIcon
  return (
    <span className={`inline-flex items-center justify-center flex-shrink-0 ${className ?? ''}`} aria-hidden="true">
      <Icon size={size} />
    </span>
  )
}
